+            // Populated / cached
+            assert!(heroes[0].team.is_loaded());
+            assert_eq!(heroes[0].team.get().unwrap().name, "Avengers");
+            assert_eq!(heroes[1].team.get().unwrap().name, "X-Men");
+            assert_eq!(heroes[2].team.get().unwrap().name, "Avengers");
